import SwiftUI

struct InsightsView: View { @EnvironmentObject private var model: LedgerViewModel; @Environment(\.locale) private var locale
    var body: some View { let transactions = model.ledger.transactions(in: model.selectedMonth); let summary = model.ledger.summary(in: model.selectedMonth); NavigationStack { List { MonthNavigator(); Section(L10n.text(.monthlyTotals)) { LabeledContent(L10n.text(.incomeLabel), value: money(summary.income, currency: model.ledger.currency ?? "USD", locale: locale)); LabeledContent(L10n.text(.expensesLabel), value: money(summary.expense, currency: model.ledger.currency ?? "USD", locale: locale)); LabeledContent(L10n.text(.netLabel), value: money(summary.net, currency: model.ledger.currency ?? "USD", locale: locale)) }; Section(L10n.text(.expensesByCategory)) { let groups = Dictionary(grouping: transactions.filter { $0.kind == .expense }, by: \.categoryName); if groups.isEmpty { Text(L10n.text(.noExpenseData)) } else { ForEach(groups.keys.sorted(), id: \.self) { name in let value = groups[name]!.reduce(Int64(0)) { $0 + $1.amountMinor }; LabeledContent(L10n.categoryName(name), value: money(value, currency: model.ledger.currency ?? "USD", locale: locale)) } } } }.navigationTitle(L10n.text(.monthlyInsights)).accessibilityLabel(L10n.text(.insightsAccessibility)) } }
}
